import{_ as t,o as a,c as o,a2 as s}from"./chunks/framework.BYVJ-AET.js";const u=JSON.parse('{"title":"Documentation Generation","description":"","frontmatter":{},"headers":[],"relativePath":"buildtools/5-builders/2-docs.md","filePath":"buildtools/5-builders/2-docs.md","lastUpdated":1776945907000}'),i={name:"buildtools/5-builders/2-docs.md"};function n(r,e,d,c,h,l){return a(),o("div",null,e[0]||(e[0]=[s(`<h1 id="documentation-generation" tabindex="-1">Documentation Generation <a class="header-anchor" href="#documentation-generation" aria-label="Permalink to &quot;Documentation Generation&quot;">​</a></h1><p>There are two types of documentation used by Source, which are the JSONs and the HTML documentation. Both are built using the <a href="https://typedoc.org" target="_blank" rel="noreferrer"><code>typedoc</code></a> tool. By reading comments and type annotations, <code>typedoc</code> is able to generate both human readable documentation and documentation in the form of JSON.</p><h2 id="typedoc-overview" tabindex="-1">Typedoc Overview <a class="header-anchor" href="#typedoc-overview" aria-label="Permalink to &quot;Typedoc Overview&quot;">​</a></h2><p>Documentation generation is a two-step process:</p><p>Firstly, the <code>buildtools build docs</code> is called on each bundle. This produces two JSON files:</p><ol><li><code>build/jsons/[bundle_name].json</code>, which is the JSON documentation used by <code>js-slang</code> and the frontend</li><li><code>docs.json</code>, which is JSON documentation format used by <code>typedoc</code> to generate the HTML documentation later</li></ol><p>Second, <code>buildtools html</code> is called, which then takes the <code>docs.json</code> files from each bundle and uses the <a href="https://typedoc.org/documents/Options.Input.html#merge" target="_blank" rel="noreferrer"><code>merge</code> entry point strategy</a> to create the HTML documentation</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Since type checking is supposed to be performed by <code>tsc</code>, <code>skipErrorChecking</code> has been set to true. This means that if there are type errors in the source files being processed, <code>typedoc</code> simply returns <code>undefined</code> when <code>Application.convert</code> is called.</p></div><p>This allows each bundle to have its own Typedoc option set.</p><h2 id="custom-checks" tabindex="-1">Custom Checks <a class="header-anchor" href="#custom-checks" aria-label="Permalink to &quot;Custom Checks&quot;">​</a></h2><p>There are two important custom checks that our documentation generation must perform:</p><h3 id="typing-variables-as-functions" tabindex="-1">Typing Variables as Functions <a class="header-anchor" href="#typing-variables-as-functions" aria-label="Permalink to &quot;Typing Variables as Functions&quot;">​</a></h3><p>Because Typedoc no longer automatically considers function-like types as functions, developers must use the <code>@function</code> tag to allow Typedoc to properly infer that a function-like variable should be documented as a function.</p><p>When generating the documentation, we simply check if the corresponding item has been assigned a variable type while having function signatures. If this is the case, then we print a warning advising the developer that they may have forgotten the <code>@function</code> tag.</p><h3 id="hiding-type-guards" tabindex="-1">Hiding Type Guards <a class="header-anchor" href="#hiding-type-guards" aria-label="Permalink to &quot;Hiding Type Guards&quot;">​</a></h3><p>Typescript has a feature called type guards that allow the compiler to better narrow types, increasing the type safety of module code.</p><p>When Typedoc encounters a type guard, it documents the return type of that type guard as is.</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> function</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> is_boolean</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">obj</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> unknown</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> obj</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> is</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> boolean</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  return</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> typeof</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> obj </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">===</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;boolean&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>The function above has its return type rendered as <code>obj is boolean</code>. However, this might confuse cadets as type guards are not a concept in Source, and the return type as rendered also hides the fact that <code>is_boolean</code> returns a <code>boolean</code> and not some other special value.</p><p>To remedy this, when generating the documentation for type guards, we simply replace the return type of the signature with <code>boolean</code> (or <code>void</code> if it&#39;s an asserts guard). This modification is done on &quot;conversion&quot; by hooking into the <code>Converter.EVENT_CREATE_SIGNATURE</code> event.</p><h2 id="html-generation" tabindex="-1">HTML Generation <a class="header-anchor" href="#html-generation" aria-label="Permalink to &quot;HTML Generation&quot;">​</a></h2><p>It is not possible to generate the HTML documentation on a per-bundle basis. Thus, when HTML documentation needs to be regenerated, the source files of every single bundle needs to be processed.</p><h2 id="json-generation" tabindex="-1">JSON Generation <a class="header-anchor" href="#json-generation" aria-label="Permalink to &quot;JSON Generation&quot;">​</a></h2><p><code>typedoc</code> represents each bundle as a <a href="https://typedoc.org/api/classes/Models.DeclarationReflection.html" target="_blank" rel="noreferrer"><code>DeclarationReflection</code></a> internally. Each of these <code>DeclarationReflection</code>s contains an array of &quot;children&quot; elements which represents that bundle&#39;s exports. Each of these elements is parsed by various parsers to produce the desired documentation object, which is then written to disk after converted into a JSON string.</p>`,24)]))}const k=t(i,[["render",n]]);export{u as __pageData,k as default};
